def _register_patch387_domains():
    """Register the 5 new business domains with the singleton WorldStateEngine."""
    try:
        from src.world_state_engine import world_state as _ws
        engine = _ws
        engine._fetchers["soc2_hipaa_changes"] = fetch_soc2_hipaa_changes
        engine._fetchers["competitive_saas"] = fetch_competitive_saas
        engine._fetchers["regulatory_general"] = fetch_regulatory_general
        engine._fetchers["construction_starts"] = fetch_construction_starts
        engine._fetchers["ashrae_nec_updates"] = fetch_ashrae_nec_updates
        return True
    except Exception:
        return False


def create_app() -> FastAPI:
    # PATCH-393: ensure exception classes in scope for inner handlers
    try:
        from fastapi import HTTPException as HTTPException  # noqa: F401
    except Exception:
        HTTPException = Exception  # type: ignore


    # PATCH-350-SYSMODULES: patch CollaborativeExecutionReport.task_id at startup
    try:
        import sys as _sys_350, importlib as _il_350
        # Force fresh import
        for _key in list(_sys_350.modules.keys()):
            if 'collaborative_task_orchestrator' in _key:
                del _sys_350.modules[_key]
        import importlib.util as _ilu
        _spec = _ilu.spec_from_file_location(
            "src.collaborative_task_orchestrator",
            "/opt/Murphy-System/src/collaborative_task_orchestrator.py"
        )
        _mod = _ilu.module_from_spec(_spec)
        _spec.loader.exec_module(_mod)
        _sys_350.modules['src.collaborative_task_orchestrator'] = _mod
        _sys_350.modules['collaborative_task_orchestrator'] = _mod
        _CER = _mod.CollaborativeExecutionReport
        import dataclasses as _dc
        _fields = {f.name for f in _dc.fields(_CER)}
        if 'task_id' not in _fields:
            _CER = _dc.make_dataclass(
                'CollaborativeExecutionReport',
                [('task_id', str, _dc.field(default=''))],
                bases=(_CER,),
            )
            def _new_post_init(self):
                if not getattr(self, 'task_id', None):
                    self.task_id = self.run_id
            _CER.__post_init__ = _new_post_init
            _mod.CollaborativeExecutionReport = _CER
            # Patch the module dict so new CTO instances use the new class
        _mod.__dict__['CollaborativeExecutionReport'] = _CER
        # Also propagate to any other loaded modules that reference it
        for _mname, _mmod in list(_sys_350.modules.items()):
            if _mmod is not None and isinstance(_mmod, type(_sys_350)) and hasattr(_mmod, 'CollaborativeExecutionReport'):
                try:
                    _mmod.__dict__['CollaborativeExecutionReport'] = _CER
                except Exception:
                    pass
        logger.info("[PATCH-350] CollaborativeExecutionReport.task_id patched ✓ fields=%s", list(_fields)[:4])
    except Exception as _e350:
        logger.warning("[PATCH-350] startup patch failed: %s", _e350)


    """Create FastAPI application"""

    if FastAPI is None:
        raise ImportError("FastAPI not installed. Install with: pip install fastapi uvicorn")

    _is_prod = os.environ.get("MURPHY_ENV", "").lower() in ("production", "staging")

    @asynccontextmanager
    async def _lifespan(app):
        """
        PATCH-122: Proper lifespan startup — runs after app is initialized.
        Starts scheduler, wires swarm, triggers first corpus collect.
        """
        import asyncio

        def _startup_tasks():
            try:
                # SwarmScheduler — must start in lifespan, not create_app()
                from src.swarm_scheduler import get_scheduler
                sched = get_scheduler()
                if not sched._started:
                    sched.start()
                    logger.info("PATCH-122: SwarmScheduler started — %d jobs", len(sched._jobs))

                # Phase 6 (2026-05-26): build URL route registry
                try:
                    from src.route_registry import build_route_index as _bri
                    _bri(app)
                except Exception as _rr_exc:
                    logger.warning("route_registry build failed: %s", _rr_exc)

                # EXEC-02 (2026-06-09): wire executive layer
                # Attaches ExecutivePlanningEngine + AgentSlotController +
                # GraphSnapshotWriter to app.state, registers 4 /api/executive
                # routes. Idempotent. Fail-soft — wiring errors are logged but
                # never crash startup.
                try:
                    from src.executive_wiring import register_executive
                    _exec_status = register_executive(app)
                    logger.info(
                        "EXEC-02: engine=%s, slots=%s, snapshots=%s, routes=%d, errors=%d",
                        _exec_status.get("engine"),
                        _exec_status.get("slot_controller"),
                        _exec_status.get("snapshot_writer"),
                        len(_exec_status.get("routes_added", [])),
                        len(_exec_status.get("errors", [])),
                    )
                except Exception as _exec_exc:
                    logger.warning("EXEC-02 wiring failed (non-fatal): %s", _exec_exc)

                # PCR-053e (2026-06-09): wire org_compiler HTTP surface
                # Attaches RoleTemplateCompiler + TelemetryCollector + ShadowLearningAgent
                # to app.state, registers 5 /api/org/* routes. Idempotent. Fail-soft —
                # wiring errors are logged but never crash startup.
                try:
                    from src.org_compiler_routes import register_org_compiler
                    _org_status = register_org_compiler(app)
                    logger.info(
                        "PCR-053e: compiler=%s, collector=%s, agent=%s, routes=%d, errors=%d",
                        _org_status.get("compiler"),
                        _org_status.get("shadow_collector"),
                        _org_status.get("shadow_agent"),
                        len(_org_status.get("routes_added", [])),
                        len(_org_status.get("errors", [])),
                    )
                except Exception as _org_exc:
                    logger.warning("PCR-053e wiring failed (non-fatal): %s", _org_exc)

                # PCR-053f (2026-06-09): wire shadow-loop heartbeat tick
                # Schedules a 10-minute periodic job that scans the shadow
                # collector, evaluates each role against the regulatory floor,
                # and writes a snapshot row to shadow_audit_snapshots. Idempotent.
                # Fail-soft - errors logged but never crash startup.
                try:
                    from src.org_compiler_heartbeat import register_heartbeat
                    _hb_status = register_heartbeat(app, interval_minutes=10)
                    # PCR-070 Stage 3: schedule perspective re-distillation
                    try:
                        from src.pcr070_perspective_heartbeat import register_heartbeat as _pcr070_register
                        _pcr070_status = _pcr070_register(app, interval_minutes=60)
                        logger.info("PCR-070 Stage 3: heartbeat status: %s", _pcr070_status)
                    except Exception as _e:
                        logger.exception("PCR-070 heartbeat registration failed: %s", _e)
                    logger.info(
                        "PCR-053f: scheduler=%s, scheduled=%s, interval=%dm, errors=%d",
                        _hb_status.get("scheduler_present"),
                        _hb_status.get("scheduled"),
                        _hb_status.get("interval_minutes"),
                        len(_hb_status.get("errors", [])),
                    )
                except Exception as _hb_exc:
                    logger.warning("PCR-053f wiring failed (non-fatal): %s", _hb_exc)


                # PCR-054c.1 (2026-06-09): wire engagement-loop HTTP surface
                # Registers 4 endpoints under /api/org/engagement{,/list,/transition}
                # backed by the EngagementFolder state machine + SQLite at
                # /var/murphy/audit/engagement_folders.db and browse mirror at
                # /var/murphy/engagements/<id>/. Idempotent + fail-soft.
                try:
                    from src.engagement_routes import register_engagement_routes
                    _eng_status = register_engagement_routes(app)
                    logger.info(
                        "PCR-054c.1: registered=%s, routes=%d, db=%s",
                        _eng_status.get("registered"),
                        len(_eng_status.get("routes_added", [])),
                        _eng_status.get("db_path"),
                    )
                except Exception as _eng_exc:
                    logger.warning("PCR-054c.1 wiring failed (non-fatal): %s", _eng_exc)


                # Rosetta Soul + Coordinator — PATCH-130: all 9 agents registered
                from src.rosetta_core import get_rosetta_soul, get_swarm_coordinator
                from src.exec_admin_agent import get_exec_admin
                from src.prod_ops_agent import get_prod_ops
                from src.collector_agent import get_collector_agent
                from src.translator_agent import get_translator_agent
                from src.scheduler_agent import get_scheduler_agent
                from src.executor_agent import get_executor_agent
                from src.auditor_agent import get_auditor_agent
                from src.hitl_agent import get_hitl_agent
                from src.rosetta_agent import get_rosetta_agent
                from src.patcher_agent import get_patcher_agent
                soul = get_rosetta_soul()
                soul.refresh_world_context()
                coord = get_swarm_coordinator()
                _agent_map = {
                    "collector":  get_collector_agent,
                    "translator": get_translator_agent,
                    "scheduler":  get_scheduler_agent,
                    "executor":   get_executor_agent,
                    "auditor":    get_auditor_agent,
                    "exec_admin": get_exec_admin,
                    "prod_ops":   get_prod_ops,
                    "hitl":       get_hitl_agent,
                    "rosetta":    get_rosetta_agent,
                    "patcher":    get_patcher_agent,
                }
                for _aid, _factory in _agent_map.items():
                    if _aid not in coord._agents:
                        try:
                            coord.register(_aid, _factory())
                        except Exception as _e:
                            logger.warning("PATCH-130: could not register agent %s: %s", _aid, _e)
                logger.info("PATCH-130: Swarm wired — %d/9 agents", len(coord._agents))
                
                # ── PATCH-ROUTE-DUP-SCAN: scan codebase for duplicate routes at boot ────
                try:
                    from src.murphy_critic import run_startup_route_scan
                    _scan_result = run_startup_route_scan()

                    # PATCH-LEARN-LOOP-WIRE-R206 + R209 (2026-05-29): activate learning feedback loop.
                    # R206 wired call at startup but it returned False (no backbone passed).
                    # R209 PATCH-LEARN-LOOP-BACKBONE-R209: try to discover an EventBackbone instance
                    # and a LearningEngine, then pass them in so the subscription actually fires.
                    try:
                        from src.learning_engine.feedback_loop_wiring import wire_feedback_loop
                        _backbone = None
                        _learning = None
                        # Try several discovery paths — first hit wins.
                        try:
                            from src.event_backbone import EventBackbone as _EB
                            _backbone = _EB()  # singleton-ish; safe to instantiate
                        except Exception as _eb_exc:
                            logger.debug("R209 backbone discovery failed: %s", _eb_exc)
                        try:
                            from src.learning_engine.learning_engine import LearningEngine as _LE
                            _learning = _LE()
                        except Exception:
                            try:
                                from src.learning_engine.learning_system import LearningEngine as _LE2
                                _learning = _LE2()
                            except Exception as _le_exc:
                                logger.debug("R209 learning_engine discovery failed: %s", _le_exc)
                        _wfl_ok = wire_feedback_loop(
                            learning_engine=_learning,
                            backbone=_backbone,
                        )
                        logger.info(
                            "PATCH-LEARN-LOOP-WIRE-R206/R209: wire_feedback_loop()=%s "
                            "(backbone=%s learning_engine=%s)",
                            _wfl_ok,
                            type(_backbone).__name__ if _backbone else None,
                            type(_learning).__name__ if _learning else None,
                        )
                    except Exception as _wfl_exc:
                        logger.warning("PATCH-LEARN-LOOP-WIRE-R206/R209: wire failed: %s", _wfl_exc)
                    # PATCH-LEARN-LOOP-MANUAL-SUBSCRIBE-R213 (2026-05-29):
                    # wire_feedback_loop() returns False because it passes string "task_completed"
                    # to backbone.subscribe() which requires EventType enum (R210 finding).
                    # Workaround: manually subscribe the handlers using EventType enum values.
                    try:
                        from src.event_backbone import EventType as _r213_EventType
                        from src.event_backbone import EventBackbone as _r213_EventBackbone
                        from src.event_backbone import get_event_backbone as _r261_get_bb  # PATCH-BACKBONE-SINGLETON-R261
                        from src.learning_engine.learning_engine import LearningEngine as _r213_LE
                        from src.learning_engine import feedback_loop_wiring as _r213_flw

                        if not getattr(_r213_flw, "_wired", False):
                            # PATCH-BACKBONE-SINGLETON-R261 (2026-05-29): R260 publishes via
                            # get_event_backbone() lazy singleton. R213 here was constructing a
                            # FRESH EventBackbone() — Murphy R261 named #4 process-wide singleton
                            # as the disconnect. Audit found get_event_backbone has proper
                            # double-checked-lock singleton (line 695-702). Use it so publishers
                            # and subscribers share one backbone. Also register with
                            # event_backbone_client so the third factory path resolves to the
                            # same instance.
                            _r213_bb = _r261_get_bb()
                            try:
                                from src.event_backbone_client import set_backbone as _r261_set_bb
                                _r261_set_bb(_r213_bb)
                                logger.info("PATCH-BACKBONE-SINGLETON-R261: event_backbone_client.set_backbone() registered canonical singleton")
                            except Exception as _r261_set_exc:
                                logger.debug("PATCH-BACKBONE-SINGLETON-R261: client set_backbone failed: %s", _r261_set_exc)
                            _r213_le_inst = _r213_LE(enable_learning=True)
                            _r213_flw._engine = _r213_le_inst
                            _r213_sub_c = _r213_bb.subscribe(
                                _r213_EventType.TASK_COMPLETED,
                                _r213_flw._on_task_completed,
                            )
                            _r213_sub_f = _r213_bb.subscribe(
                                _r213_EventType.TASK_FAILED,
                                _r213_flw._on_task_failed,
                            )
                            _r213_flw._wired = True
                            logger.info(
                                "PATCH-LEARN-LOOP-MANUAL-SUBSCRIBE-R213: wired completed=%s failed=%s",
                                _r213_sub_c, _r213_sub_f,
                            )
                            # PATCH-BACKBONE-START-R219 (2026-05-29): R218 status showed
                            # background_loop_running=False — published events queue but never
                            # dispatch. Call bb.start() to launch the dispatch loop.
                            try:
                                if hasattr(_r213_bb, "start"):
                                    _r213_bb.start()
                                    _r213_status = _r213_bb.get_status() if hasattr(_r213_bb, "get_status") else {}
                                    logger.info(
                                        "PATCH-BACKBONE-START-R219: bb.start() called, loop_running=%s",
                                        _r213_status.get("background_loop_running"),
                                    )
                            except Exception as _r219_exc:
                                logger.warning("PATCH-BACKBONE-START-R219: start failed: %s", _r219_exc)
                        else:
                            logger.debug("PATCH-LEARN-LOOP-MANUAL-SUBSCRIBE-R213: already wired")
                    except Exception as _r213_exc:
                        logger.warning("PATCH-LEARN-LOOP-MANUAL-SUBSCRIBE-R213: failed: %s", _r213_exc)
                    if _scan_result.get('findings', 0) > 0:
                        logger.warning(
                            "PATCH-ROUTE-DUP-SCAN: %d duplicate route(s) found — see murphy_audit.events",
                            _scan_result['findings'],
                        )
                    else:
                        logger.info(
                            "PATCH-ROUTE-DUP-SCAN: clean — %d files scanned in %dms",
                            _scan_result.get('files_scanned', 0),
                            _scan_result.get('duration_ms', 0),
                        )
                except Exception as _scan_err:
                    logger.warning("PATCH-ROUTE-DUP-SCAN: %s", _scan_err)

                # PATCH-170d: Start Redis bus listeners for each agent domain
                try:
                    from src.swarm_bus import get_listener
                    _domain_map = {
                        "exec_admin": ["exec_admin"],
                        "prod_ops":   ["prod_ops", "collector"],
                        "auditor":    ["auditor"],
                        "hitl":       ["hitl"],
                        "rosetta":    ["system", "planning"],
                    }
                    def _make_dispatch_cb(_coord):
                        def _cb(signal):
                            try:
                                _coord.dispatch(signal)
                            except Exception as _e:
                                pass
                        return _cb
                    _dispatch_cb = _make_dispatch_cb(coord)
                    for _aid, _domains in _domain_map.items():
                        _listener = get_listener(_aid, _domains)
                        _listener.start(_dispatch_cb)
                    logger.info("PATCH-170d: Bus listeners started for %d agents", len(_domain_map))
                except Exception as _be:
                    logger.warning("PATCH-170d: Bus listener startup failed: %s", _be)

                # PATCH-170d: Seed org chart DB from Rosetta CHARACTERS
                try:
                    import sqlite3 as _sq
                    _oc_db = "/var/lib/murphy-production/orgchart.db"
                    _oc = _sq.connect(_oc_db, timeout=5)
                    _oc.execute("""
                        CREATE TABLE IF NOT EXISTS positions (
                            id TEXT PRIMARY KEY,
                            position INTEGER,
                            name TEXT,
                            emoji TEXT,
                            role TEXT,
                            department TEXT,
                            tone TEXT,
                            bias TEXT,
                            hitl_threshold REAL,
                            reports_to TEXT,
                            updated_at TEXT
                        )
                    """)
                    _ROLE_LABELS = {
                        "rosetta":"Chief Alignment Officer","exec_admin":"Executive Operations",
                        "auditor":"Chief Auditor","hitl":"Human-in-the-Loop Gate",
                        "prod_ops":"Production Operations","executor":"Task Executor",
                        "scheduler":"Workflow Scheduler","translator":"Signal Translator",
                        "collector":"Signal Collector",
                    }
                    _DEPT_MAP = {
                        "rosetta":"Governance","exec_admin":"Operations","auditor":"Compliance",
                        "hitl":"Safety","prod_ops":"Engineering","executor":"Engineering",
                        "scheduler":"Operations","translator":"Intelligence","collector":"Intelligence",
                    }
                    _REPORTS_TO = {
                        "exec_admin":"rosetta","auditor":"rosetta","hitl":"rosetta",
                        "prod_ops":"exec_admin","executor":"exec_admin","scheduler":"exec_admin",
                        "translator":"collector","collector":"prod_ops",
                    }
                    _now_iso = __import__('datetime').datetime.utcnow().isoformat()
                    for _ch in soul.CHARACTERS.values():
                        _oc.execute("""
                            INSERT OR REPLACE INTO positions
                            (id, position, name, emoji, role, department, tone, bias, hitl_threshold, reports_to, updated_at)
                            VALUES (?,?,?,?,?,?,?,?,?,?,?)
                        """, (
                            _ch.agent_id, _ch.position, _ch.name, _ch.emoji,
                            _ROLE_LABELS.get(_ch.agent_id, _ch.name),
                            _DEPT_MAP.get(_ch.agent_id, "Operations"),
                            _ch.tone, _ch.bias, _ch.hitl_threshold,
                            _REPORTS_TO.get(_ch.agent_id), _now_iso,
                        ))
                    _oc.commit()
                    _oc.close()
                    logger.info("PATCH-170d: Org chart DB seeded — 9 positions")
                except Exception as _oe:
                    logger.warning("PATCH-170d: Org chart DB seed failed: %s", _oe)

                # WorldCorpus — init + immediate refresh if stale
                from src.world_corpus import get_world_corpus
                wc = get_world_corpus()
                _wc_stats = wc.stats()
                logger.info("PATCH-130: WorldCorpus ready — %d records", _wc_stats["total_records"])
                # PATCH-130: trigger an immediate collect if corpus has fewer than 100 records
                if _wc_stats.get("total_records", 0) < 100:
                    try:
                        counts = wc.collect_all()
                        logger.info("PATCH-130: WorldCorpus refreshed at startup — %s", counts)
                    except Exception as _exc:
                        logger.warning("PATCH-130: WorldCorpus startup collect failed: %s", _exc)

            except Exception as exc:
                logger.error("PATCH-122: lifespan startup error: %s", exc)

        import threading
        t = threading.Thread(target=_startup_tasks, daemon=True, name="murphy-lifespan-startup")
        t.start()
        t.join(timeout=30)  # wait max 30s for startup tasks

        # MurphyMind — continuous self-awareness loop
        try:
            from src.murphy_mind import get_mind
            get_mind().start()
            logger.info("PATCH-124: MurphyMind started -- 10min self-awareness cycle")
        except Exception as _me:
            logger.warning("PATCH-124: MurphyMind startup failed: %s", _me)


        # PATCH-351: Capacity Watchdog + Offering/Capability Alignment
        try:
            from src.capacity_watchdog import start_capacity_watchdog
            start_capacity_watchdog()
            logger.info("PATCH-351: Capacity watchdog started — 5min interval, 10 alert rules")
        except Exception as _cwe:
            logger.warning("PATCH-351: Capacity watchdog startup failed: %s", _cwe)

        yield  # app is now running
        # shutdown: nothing to tear down (scheduler threads are daemon)

