    @app.get("/api/public/stats")
    async def public_stats():
        """PATCH-451: Public landing-page hero metrics — fixed sources.

        Reads:
          swarm_agents       <- src.rosetta_core.get_swarm_coordinator()
          mind_*             <- src.murphy_mind.get_mind().stats()
          crm_deals          <- sqlite /var/lib/murphy-production/crm.db
          mfgc_gates_*       <- murphy.get_mfgc_state()
        """
        out = {
            "swarm_agents": 0,
            "mind_confidence": 0.0,
            "mind_avg_confidence": 0.0,
            "mind_cycle": 0,
            "crm_deals": 0,
            "mfgc_gates_open": 0,
            "mfgc_gates_total": 0,
            "hitl_pending": 0,           # SLICE-F Pillar-5 (R76b)
            "ledger_entries": 0,         # SLICE-F Pillar-5 (R76b)
            "system_status": "operational",
            "degraded_components": [],
        }
        # ── swarm agents ──
        try:
            from src.rosetta_core import get_swarm_coordinator as _gsc
            coord = _gsc()
            if coord is not None:
                agents = getattr(coord, "agents", None) or getattr(coord, "_agents", None) or {}
                if isinstance(agents, dict):
                    out["swarm_agents"] = len(agents)
                elif isinstance(agents, (list, tuple)):
                    out["swarm_agents"] = len(agents)
        except Exception:
            out["degraded_components"].append("swarm")
        # ── mind (use the .stats() interface that already powers /api/swarm/mind/status) ──
        try:
            from src.murphy_mind import get_mind
            s = get_mind().stats() or {}
            latest = s.get("latest_cycle") or {}
            out["mind_confidence"] = float(latest.get("confidence") or 0.0)
            out["mind_cycle"] = int(latest.get("cycle") or s.get("cycle") or 0)
            out["mind_avg_confidence"] = float(s.get("avg_confidence") or 0.0)
        except Exception:
            out["degraded_components"].append("mind")
        # ── crm deals (sqlite at the known production path) ──
        try:
            import sqlite3
            conn = sqlite3.connect("/var/lib/murphy-production/crm.db", timeout=2)
            row = conn.execute("SELECT COUNT(*) FROM deals").fetchone()
            conn.close()
            if row:
                out["crm_deals"] = int(row[0])
        except Exception:
            out["degraded_components"].append("crm")
        # ── MFGC gates (replicate /api/mfgc/gates logic locally) ──
        try:
            cfg = getattr(murphy, "mfgc_config", {}) or {}
            enabled = bool(cfg.get("enabled", False))
            threshold = float(cfg.get("murphy_threshold", 0.6))
            mind_running, mind_conf, mind_cycle = False, 0.0, 0
            try:
                from src.murphy_mind import get_mind as _gm2
                _s = _gm2().stats() or {}
                mind_running = bool(_s.get("running", False))
                mind_conf    = float(_s.get("avg_confidence") or _s.get("confidence") or 0.0)
                mind_cycle   = int(_s.get("cycle") or _s.get("total_cycles") or 0)
            except Exception:
                pass
            shield_layers = 19  # baseline from commission
            gate_results = {
                "executive":  enabled and mind_conf >= 0.70,
                "operations": enabled and mind_running and mind_cycle > 0,
                "qa":         shield_layers >= 18,
                "hitl":       enabled,
                "compliance": enabled and shield_layers >= 18,
                "budget":     threshold <= 0.75,
            }
            out["mfgc_gates_total"] = len(gate_results)
            out["mfgc_gates_open"]  = sum(1 for v in gate_results.values() if v)
        except Exception:
            out["degraded_components"].append("mfgc")
        # ── overall status ──
        if len(out["degraded_components"]) >= 3:
            out["system_status"] = "degraded"
        elif len(out["degraded_components"]) >= 1:
            out["system_status"] = "partial"
        # ── HITL pending (SLICE-F Pillar-5 R76b) — use the SAME source the
        # live /api/swarm/hitl/pending endpoint uses (hitl_gate_swarm.get_hitl_queue)
        try:
            from src.hitl_gate_swarm import get_hitl_queue as _ghq
            _q = _ghq()
            _stats = _q.stats() or {}
            # stats has shape {"total": N, "by_status": {"pending": N}}
            out["hitl_pending"] = int((_stats.get("by_status") or {}).get("pending", 0))
        except Exception:
            out["degraded_components"].append("hitl")

        # ── PSM ledger entries (SLICE-F Pillar-5 R76b) — the ledger is a
        # JSONL file (not sqlite). Use SelfEditLedger.read_all() — the same
        # method the live /api/platform/self-modification/ledger endpoint
        # uses. Try the resolved path first, then the known production path.
        try:
            from src.platform_self_modification.endpoint import (
                SelfEditLedger as _SEL,
                _resolve_ledger_path as _rlp,
            )
            import os as _os
            _candidates = [
                _rlp(),
                "/var/lib/murphy-production/platform_self_edit_ledger.jsonl",
                "/opt/Murphy-System/data/platform_self_edit_ledger.jsonl",
            ]
            for _lp in _candidates:
                if _lp and _os.path.exists(_lp):
                    _ledger = _SEL(_lp)
                    if hasattr(_ledger, "read_all"):
                        _entries = _ledger.read_all() or []
                        out["ledger_entries"] = len(_entries)
                        break
        except Exception:
            out["degraded_components"].append("ledger")

        return JSONResponse(out)

    @app.get("/os", include_in_schema=False)
    async def _murphy_os_page(request: Request):
        """Murphy OS — serves the modern 96KB Autonomous Operations dashboard.
        2026-05-27: rewired from old 41KB Command Center to the static modern
        dashboard at /static/murphy-os.html (47 live API hooks vs 12 in old)."""
        import os as _osp350
        from fastapi.responses import FileResponse as _FR350, HTMLResponse as _HR350
        modern = "/opt/Murphy-System/static/murphy-os.html"
        if _osp350.path.isfile(modern):
            return _FR350(modern, media_type="text/html")
        legacy = "/opt/Murphy-System/murphy_os.html"
        if _osp350.path.isfile(legacy):
            with open(legacy, "r", encoding="utf-8") as _f350:
                return _HR350(_f350.read())
        return _HR350("<h1>Murphy OS loading...</h1>")



