        categories = {}
        for cmd in catalog:
            cat = cmd["category"]
            if cat not in categories:
                categories[cat] = []
            categories[cat].append(cmd)

        return JSONResponse({
            "success": True,
            "total_commands": len(catalog),
            "categories": list(categories.keys()),
            "catalog": catalog,
        })

