    # ══════════════════════════════════════════════════════════════════════
    # AUTH MIDDLEWARE — ADR-0012 Release N
    # OIDC primary (Bearer JWT) + session cookie + deprecated X-API-Key
    # fallback gated by MURPHY_ALLOW_API_KEY (default true) and a
    # route allowlist (default /api/v1/internal/*).
    # ══════════════════════════════════════════════════════════════════════

    try:
        from auth_middleware import OIDCAuthMiddleware as _OIDCMW  # type: ignore
    except Exception:
        try:
            from src.auth_middleware import OIDCAuthMiddleware as _OIDCMW  # type: ignore
        except Exception as _oidc_imp_exc:
            _OIDCMW = None  # type: ignore[assignment]
            logger.warning(
                "OIDCAuthMiddleware import failed (%s) — using legacy inline guard",
                _oidc_imp_exc,
            )

    if _OIDCMW is not None:
        app.add_middleware(_OIDCMW)
        # PATCH-351b: Growth + capacity routes are public (exempt from auth)
        # PATCH-351b: Growth routes exempt from auth
        try:
            _OIDCMW.EXEMPT_PATHS.update({
                "/api/growth/onboard", "/api/growth/investor-inquiry",
                "/api/growth/partner-inquiry", "/api/growth/outreach",
                "/api/health/capacity", "/api/oo/survey",
                # _R444_OIDC_EXEMPT — public marketplace + audit endpoints
                "/api/marketplace/agents",
                "/api/marketplace/categories",
                "/api/marketplace/vote",  # handler does its own 401 if anon
                "/marketplace",
                "/api/audit/request",
                # _R445_OIDC_EXEMPT — public tenant slug endpoints
                "/api/tenant/check-slug",
                # _R489C_EXEMPT — public contact form
                "/api/contact/submit",
            })
            _pfx = ("/api/growth", "/api/oo/", "/api/health/capacity",
                    "/api/marketplace/",
                    "/api/tenant/by-slug/",
                    "/api/download/")  # R482
            _OIDCMW.EXEMPT_PREFIXES = tuple(set(_OIDCMW.EXEMPT_PREFIXES)|set(_pfx))
        except Exception:
            pass

        # PATCH-194b: Lowercase path redirect — /UI/ /API/ /Static/ etc → lowercase
        try:
            from starlette.middleware.base import BaseHTTPMiddleware as _BMW194b
            from starlette.responses import RedirectResponse as _RR194b

            class _CaseMW(_BMW194b):
                async def dispatch(self, request, call_next):
                    path = request.url.path
                    lower = path.lower()
                    if path.startswith("/verify/"):
                        # Ship 31v: preserve token case
                        pass
                    elif path != lower:
                        qs = request.url.query
                        return _RR194b(lower + ("?" + qs if qs else ""), status_code=301)
                    return await call_next(request)

            app.add_middleware(_CaseMW)
            logger.info("[PATCH-194b] Case-insensitive URL middleware active")
        except Exception as _e194b:
            logger.warning("[PATCH-194b] Case middleware skipped: %s", _e194b)
    else:
        # PATCH-411 cleanup (2026-05-24): the legacy inline _APIKeyMiddleware
        # fallback (57 lines) was deleted. It only ever fired if
        # auth_middleware.OIDCAuthMiddleware failed to import, which has
        # never happened in production. If you hit this branch, the
        # canonical OIDC import path is broken — fix the import, do NOT
        # silently fall back to an unauthenticated server.
        logger.error(
            "auth_middleware.OIDCAuthMiddleware unavailable — "
            "refusing to start with no auth middleware. "
            "Check that /opt/Murphy-System/src is on PYTHONPATH."
        )
        raise RuntimeError(
            "OIDCAuthMiddleware import failed — refusing to start without auth. "
            "See PATCH-411 cleanup notes."
        )

    # ══════════════════════════════════════════════════════════════════════
    # EXCEPTION HANDLERS — normalise all error formats into standard envelope
    # ══════════════════════════════════════════════════════════════════════

    from fastapi import Request as _FARequest
    from fastapi.exceptions import RequestValidationError as _RVE
    from starlette.exceptions import HTTPException as _SHTTPException

    @app.exception_handler(_SHTTPException)
    async def _http_exception_handler(_req: _FARequest, exc: _SHTTPException):
        return JSONResponse(
            {"success": False, "error": {"code": f"HTTP_{exc.status_code}", "message": str(exc.detail)}},
            status_code=exc.status_code,
        )

    @app.exception_handler(_RVE)
    async def _validation_exception_handler(_req: _FARequest, exc: _RVE):
        return JSONResponse(
            {"success": False, "error": {"code": "VALIDATION_ERROR", "message": str(exc)}},
            status_code=422,
        )

    @app.exception_handler(Exception)
    async def _general_exception_handler(_req: _FARequest, exc: Exception):
        logger.error("Unhandled exception: %s", exc, exc_info=True)
        return JSONResponse(
            {"success": False, "error": {"code": "INTERNAL_ERROR", "message": "Internal server error"}},
            status_code=500,
        )

    # ══════════════════════════════════════════════════════════════════════
    # STUB ENDPOINTS — frontend calls that are not yet fully implemented
    # All return 501 Not Implemented with a clear error code.
